    // COI Reference Frame Correction
    double coi_total_2H = 87.360000 + 50.661600 + 60.408920 + 67.198560 + 56.170400 + 75.564720 + 54.130560 + 47.151720 + 116.202900 + 1199.000000;
    double coi_omega = (87.360000 * x[1] + 50.661600 * x[7] + 60.408920 * x[13] + 67.198560 * x[19] + 56.170400 * x[25] + 75.564720 * x[31] + 54.130560 * x[37] + 47.151720 * x[43] + 116.202900 * x[49] + 1199.000000 * x[55]) / coi_total_2H;
    double omega_b_sys = 2.0 * M_PI * 60.0;
    dxdt[0] -= omega_b_sys * (coi_omega - 1.0);
    dxdt[6] -= omega_b_sys * (coi_omega - 1.0);
    dxdt[12] -= omega_b_sys * (coi_omega - 1.0);
    dxdt[18] -= omega_b_sys * (coi_omega - 1.0);
